+        let message = JsonRpcMessage::Request(request);
+        if let Err(e) = transport.send(&cx, &message) {
+            log::error!(
+                target: targets::TRANSPORT,
+                "Failed to send notification: {}",
+                e
+            );
+        }
+    })
+}
